'use client';

import { useEffect, useState, Suspense } from 'react';
import { useSearchParams } from 'next/navigation';
import Link from 'next/link';
import { Zap, ArrowRight, ShoppingBag, Users } from 'lucide-react';
import ProductCard from '@/components/ProductCard';
import { ProductCardSkeleton } from '@/components/SkeletonLoader';
import FilterSidebar from '@/components/FilterSidebar';
import { getProducts } from '@/mock/api';
import { empresa } from '@/mock/data';
import type { Produto } from '@/types';
import styles from './page.module.scss';

function HomeContent() {
  const searchParams = useSearchParams();
  const [products, setProducts] = useState<Produto[]>([]);
  const [total, setTotal] = useState(0);
  const [loading, setLoading] = useState(true);
  const [filters, setFilters] = useState<{
    categoria?: string;
    precoMin?: number;
    precoMax?: number;
    search?: string;
  }>({});

  const categoriaParam = searchParams.get('categoria');
  const searchParam = searchParams.get('search');

  useEffect(() => {
    setFilters(prev => ({
      ...prev,
      categoria: categoriaParam || undefined,
      search: searchParam || undefined,
    }));
  }, [categoriaParam, searchParam]);

  useEffect(() => {
    setLoading(true);
    getProducts({ ...filters, limit: 40 }).then(res => {
      setProducts(res.products);
      setTotal(res.total);
      setLoading(false);
    });
  }, [filters]);

  const handleFilter = (newFilters: { categoria?: string; precoMin?: number; precoMax?: number }) => {
    setFilters(prev => ({ ...prev, ...newFilters }));
  };

  return (
    <>
      {/* Hero Section */}
      <section className={styles.hero}>
        <div className={styles.heroInner}>
          <div className={styles.heroBadge}>
            <Zap size={14} /> Marketplace Esportivo Premium
          </div>
          <h1 className={styles.heroTitle}>
            Tudo para o esporte em um só lugar
          </h1>
          <p className={styles.heroSubtitle}>
            Encontre os melhores produtos esportivos dos melhores vendedores.
            Converse direto pelo WhatsApp.
          </p>
          <div className={styles.heroActions}>
            <a href="#produtos" className={styles.heroCta}>
              <ShoppingBag size={18} />
              Explorar Produtos
            </a>
            <Link href="/vendedores" className={styles.heroSecondary}>
              <Users size={18} />
              Ver Vendedores
            </Link>
          </div>
        </div>
      </section>

      {/* Products Grid */}
      <section id="produtos" className={styles.main}>
        <div className={styles.layout}>
          <FilterSidebar
            selectedCategoria={filters.categoria}
            precoMin={filters.precoMin}
            precoMax={filters.precoMax}
            onFilter={handleFilter}
          />

          <div className={styles.content}>
            <div className={styles.sectionHeader}>
              <h2 className={styles.sectionTitle}>
                Produtos <span>em destaque</span>
              </h2>
              {!loading && (
                <span className={styles.resultCount}>{total} produtos encontrados</span>
              )}
            </div>

            {loading ? (
              <div className={styles.loadingGrid}>
                {Array.from({ length: 8 }).map((_, i) => (
                  <ProductCardSkeleton key={i} />
                ))}
              </div>
            ) : products.length > 0 ? (
              <div className={styles.grid}>
                {products.map((product, i) => (
                  <ProductCard key={product.id} product={product} index={i} />
                ))}
              </div>
            ) : (
              <div className={styles.empty}>
                <ShoppingBag size={48} />
                <p>Nenhum produto encontrado</p>
              </div>
            )}
          </div>
        </div>
      </section>

      {/* Sell CTA Banner */}
      {empresa.linkGrupoDevenda && (
        <section className={styles.sellBanner}>
          <div className={styles.sellBannerInner}>
            <h2 className={styles.sellTitle}>Deseja vender seus produtos?</h2>
            <p className={styles.sellText}>
              Entre no nosso grupo de vendas e comece a anunciar agora mesmo.
            </p>
            <a
              href={empresa.linkGrupoDevenda}
              target="_blank"
              rel="noopener noreferrer"
              className={styles.sellBtn}
            >
              Quero vender <ArrowRight size={18} />
            </a>
          </div>
        </section>
      )}
    </>
  );
}

export default function HomePage() {
  return (
    <Suspense>
      <HomeContent />
    </Suspense>
  );
}
